use datastream::chunked::Chunked;

#[test]
fn test_exact_chunks() {
    let data = vec![1, 2, 3, 4, 5, 6];
    let chunks: Vec<Vec<i32>> = data.into_iter().chunks(3).collect();
    assert_eq!(chunks, vec![vec![1, 2, 3], vec![4, 5, 6]]);
}

#[test]
fn test_partial_last_chunk() {
    let data = vec![1, 2, 3, 4, 5];
    let chunks: Vec<Vec<i32>> = data.into_iter().chunks(3).collect();
    assert_eq!(chunks, vec![vec![1, 2, 3], vec![4, 5]]);
}

#[test]
fn test_single_element_chunks() {
    let data = vec![10, 20, 30];
    let chunks: Vec<Vec<i32>> = data.into_iter().chunks(1).collect();
    assert_eq!(chunks, vec![vec![10], vec![20], vec![30]]);
}

#[test]
fn test_chunk_larger_than_data() {
    let data = vec![1, 2];
    let chunks: Vec<Vec<i32>> = data.into_iter().chunks(10).collect();
    assert_eq!(chunks, vec![vec![1, 2]]);
}

#[test]
fn test_empty_iterator() {
    let data: Vec<i32> = vec![];
    let chunks: Vec<Vec<i32>> = data.into_iter().chunks(3).collect();
    assert!(chunks.is_empty());
}

#[test]
fn test_with_strings() {
    let data = vec!["a", "b", "c", "d"];
    let chunks: Vec<Vec<&str>> = data.into_iter().chunks(2).collect();
    assert_eq!(chunks, vec![vec!["a", "b"], vec!["c", "d"]]);
}

pub struct ChunkedIterator<I: Iterator> {
    iter: I,
    chunk_size: usize,
}

impl<I: Iterator> Iterator for ChunkedIterator<I> {
    type Item = Vec<I::Item>;

    fn next(&mut self) -> Option<Self::Item> {
        let mut chunk = Vec::with_capacity(self.chunk_size);
        for _ in 0..self.chunk_size {
            match self.iter.next() {
                Some(item) => chunk.push(item),
                None => break,
            }
        }
        if chunk.is_empty() {
            None
        } else {
            Some(chunk)
        }
    }
}

pub trait Chunked: Iterator + Sized {
    fn chunks(self, size: usize) -> ChunkedIterator<Self> {
        ChunkedIterator {
            iter: self,
            chunk_size: size,
        }
    }
}

impl<I: Iterator> Chunked for I {}

